import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { Container, Row, Col, Form, Alert } from "react-bootstrap";
import { toast } from "react-toastify";
import { userAPI, orderAPI } from "../services/api";
import { useCart } from "../context/CartContext";

const CheckoutPage = () => {
  const [addresses, setAddresses] = useState([]);
  const [selectedAddress, setSelectedAddress] = useState("");
  const [paymentMethod, setPaymentMethod] = useState("COD");
  const [loading, setLoading] = useState(false);

  const [newAddress, setNewAddress] = useState({
    name: "",
    phone: "",
    addressLine1: "",
    city: "",
    state: "",
    pincode: "",
    country: "India",
  });

  const [showNewAddress, setShowNewAddress] = useState(false);

  const { cart } = useCart();
  const navigate = useNavigate();

  useEffect(() => {
    const fetchAddresses = async () => {
      try {
        const response = await userAPI.getAddresses();

        console.log("Address API Response:", response.data);

        let addressList = [];

        if (Array.isArray(response.data)) {
          addressList = response.data;
        } else if (response.data && Array.isArray(response.data.data)) {
          addressList = response.data.data;
        } else if (response.data && response.data.id) {
          addressList = [response.data];
        }

        setAddresses(addressList);

        if (addressList.length > 0) {
          setSelectedAddress(addressList[0].id);
        }
      } catch (error) {
        console.error(error);
        setAddresses([]);
      }
    };

    fetchAddresses();
  }, []);

  const handleAddAddress = async () => {
    try {
      const res = await userAPI.addAddress(newAddress);

      setAddresses((prev) => [...prev, res.data]);
      setSelectedAddress(res.data.id);

      setShowNewAddress(false);

      setNewAddress({
        name: "",
        phone: "",
        addressLine1: "",
        city: "",
        state: "",
        pincode: "",
        country: "India",
      });

      toast.success("Address added successfully!");
    } catch (err) {
      toast.error("Failed to add address");
    }
  };

  const handlePlaceOrder = async () => {
    if (!selectedAddress) {
      toast.error("Please select a delivery address");
      return;
    }

    setLoading(true);

    try {
      const res = await orderAPI.placeOrder({
        addressId: selectedAddress,
        paymentMethod,
      });

      toast.success("Order placed successfully!");
      navigate(`/orders/${res.data.id}`);
    } catch (err) {
      toast.error(err.response?.data?.message || "Failed to place order");
    } finally {
      setLoading(false);
    }
  };

  const shippingFee = cart.totalAmount > 499 ? 0 : 49;
  const finalTotal = Number(cart.totalAmount || 0) + shippingFee;

  return (
    <Container className="py-4">
      <h3
        style={{
          fontFamily: "Syne, sans-serif",
          fontWeight: 800,
        }}
      >
        Checkout
      </h3>

      <Row className="g-4 mt-1">
        <Col lg={8}>
          {/* Delivery Address */}
          <div
            style={{
              background: "white",
              borderRadius: "var(--nk-radius)",
              padding: "1.5rem",
              boxShadow: "var(--nk-shadow)",
              marginBottom: "1.5rem",
            }}
          >
            <h5
              style={{
                fontFamily: "Syne, sans-serif",
                fontWeight: 700,
              }}
            >
              📍 Delivery Address
            </h5>

            {addresses.length > 0 ? (
              addresses.map((addr) => (
                <div
                  key={addr.id}
                  className="d-flex align-items-start gap-2 p-2 mb-2"
                  style={{
                    border:
                      selectedAddress === addr.id
                        ? "2px solid var(--nk-primary)"
                        : "2px solid #eee",
                    borderRadius: 8,
                    cursor: "pointer",
                  }}
                  onClick={() => setSelectedAddress(addr.id)}
                >
                  <input
                    type="radio"
                    checked={selectedAddress === addr.id}
                    onChange={() => setSelectedAddress(addr.id)}
                  />

                  <div>
                    <strong>{addr.name}</strong> | {addr.phone}
                    <br />
                    <small style={{ color: "#6c757d" }}>
                      {addr.addressLine1}, {addr.city}, {addr.state} -{" "}
                      {addr.pincode}
                    </small>
                  </div>
                </div>
              ))
            ) : (
              <Alert variant="warning">
                No saved addresses found. Please add a new address.
              </Alert>
            )}

            <button
              onClick={() => setShowNewAddress(!showNewAddress)}
              style={{
                background: "none",
                border: "2px dashed #ccc",
                borderRadius: 8,
                padding: "0.5rem 1rem",
                cursor: "pointer",
                color: "var(--nk-primary)",
                fontWeight: 600,
                width: "100%",
                marginTop: "0.5rem",
              }}
            >
              + Add New Address
            </button>

            {showNewAddress && (
              <div className="mt-3">
                <Row className="g-2">
                  <Col sm={6}>
                    <Form.Control
                      placeholder="Full Name"
                      value={newAddress.name}
                      onChange={(e) =>
                        setNewAddress((prev) => ({
                          ...prev,
                          name: e.target.value,
                        }))
                      }
                    />
                  </Col>

                  <Col sm={6}>
                    <Form.Control
                      placeholder="Phone"
                      value={newAddress.phone}
                      onChange={(e) =>
                        setNewAddress((prev) => ({
                          ...prev,
                          phone: e.target.value,
                        }))
                      }
                    />
                  </Col>

                  <Col sm={12}>
                    <Form.Control
                      placeholder="Address Line 1"
                      value={newAddress.addressLine1}
                      onChange={(e) =>
                        setNewAddress((prev) => ({
                          ...prev,
                          addressLine1: e.target.value,
                        }))
                      }
                    />
                  </Col>

                  <Col sm={4}>
                    <Form.Control
                      placeholder="City"
                      value={newAddress.city}
                      onChange={(e) =>
                        setNewAddress((prev) => ({
                          ...prev,
                          city: e.target.value,
                        }))
                      }
                    />
                  </Col>

                  <Col sm={4}>
                    <Form.Control
                      placeholder="State"
                      value={newAddress.state}
                      onChange={(e) =>
                        setNewAddress((prev) => ({
                          ...prev,
                          state: e.target.value,
                        }))
                      }
                    />
                  </Col>

                  <Col sm={4}>
                    <Form.Control
                      placeholder="Pincode"
                      value={newAddress.pincode}
                      onChange={(e) =>
                        setNewAddress((prev) => ({
                          ...prev,
                          pincode: e.target.value,
                        }))
                      }
                    />
                  </Col>

                  <Col sm={12}>
                    <button
                      className="btn-nk-primary"
                      onClick={handleAddAddress}
                    >
                      Save Address
                    </button>
                  </Col>
                </Row>
              </div>
            )}
          </div>
        </Col>

        <Col lg={4}>
          <div
            style={{
              background: "white",
              borderRadius: "var(--nk-radius)",
              padding: "1.5rem",
              boxShadow: "var(--nk-shadow)",
            }}
          >
            <h5>Order Summary</h5>

            <div className="d-flex justify-content-between">
              <span>Subtotal</span>
              <span>₹{Number(cart.totalAmount).toLocaleString("en-IN")}</span>
            </div>

            <div className="d-flex justify-content-between">
              <span>Delivery</span>
              <span>{shippingFee === 0 ? "FREE" : `₹${shippingFee}`}</span>
            </div>

            <hr />

            <div
              className="d-flex justify-content-between"
              style={{ fontWeight: "bold" }}
            >
              <span>Total</span>
              <span>₹{finalTotal.toLocaleString("en-IN")}</span>
            </div>

            <button
              className="btn-nk-primary w-100 mt-3"
              onClick={handlePlaceOrder}
              disabled={loading}
            >
              {loading ? "Placing Order..." : "Place Order"}
            </button>
          </div>
        </Col>
      </Row>
    </Container>
  );
};

export default CheckoutPage;
